const { access } = require("node:fs/promises");
const path = require("node:path");
const { pathToFileURL } = require("node:url");

const base = path.resolve(
  process.env.CLAUDE_PLUGIN_ROOT ||
    process.env.CODEX_PLUGIN_ROOT ||
    process.env.PLUGIN_ROOT ||
    process.cwd()
);

const searchDirs = [];
let dir = base;
for (let i = 0; i < 6; i++) {
  searchDirs.push(dir);
  const parent = path.dirname(dir);
  if (parent === dir) {
    break;
  }
  dir = parent;
}

const candidates = [];
for (const root of searchDirs) {
  candidates.push(path.join(root, "runtime", "dist", "server.js"));
  candidates.push(
    path.join(root, "plugins", "claude-interrogate", "runtime", "dist", "server.js")
  );
}

(async () => {
  let serverPath;
  for (const candidate of candidates) {
    try {
      await access(candidate);
      serverPath = candidate;
      break;
    } catch {
      // continue
    }
  }

  if (!serverPath) {
    throw new Error(
      "Could not locate runtime/dist/server.js from base: " +
        base +
        " (checked: " +
        candidates.join(", ") +
        ")"
    );
  }

  process.argv[1] = serverPath;

  await import(pathToFileURL(serverPath).href);
})().catch((error) => {
  console.error(error instanceof Error ? error.stack || error.message : String(error));
  process.exit(1);
});
